float freq = 2.5;
float amp = 0.2;
vector noisepos = @P * freq;
float n = noise(noisepos);
@P += @N * n * amp;

int n = 100;
float turns = 3.0;
float height = 3.0;
float radius = 1.0;
for(int i=0; i<n; i++){
  float t = float(i)/float(n-1);
  float angle = t * turns * PI * 2;
  vector pos = set(cos(angle)*radius, t*height, sin(angle)*radius);
  int pt = addpoint(0, pos);
}
removeprim(0, 0, 1);
for(int i=0; i<n-1; i++){
  addprim(0, "polyline", i, i+1);
}

float ymin = -1.0;
float ymax = 1.0;
float t = fit(@P.y, ymin, ymax, 0.0, 1.0);
vector red = {1, 0.1, 0.05};
vector blue = {0.05, 0.3, 1.0};
@Cd = lerp(red, blue, t);

int n = 500;
float T = @Time;
for(int i=0; i<n; i++){
  float seed = float(i);
  float spd = fit01(rand(seed), 0.5, 3.0);
  float lat = fit01(rand(seed+0.1), 0, PI);
  float lon = fit01(rand(seed+0.2), 0, PI*2);
  vector dir = set(sin(lat)*cos(lon), cos(lat), sin(lat)*sin(lon));
  vector pos = dir * spd * T;
  int pt = addpoint(0, pos);
  setpointattrib(0, 'v', pt, dir*spd);
}
removeprim(0,0,1);

