vector center = {0,0,0};
float maxdist = 2.0;
float d = distance(@P, center);
float falloff = 1.0 - clamp(d / maxdist, 0, 1);
@P.y += falloff * 0.5;

int npts[] = pcfind(0, 'P', @P, 0.5, 5);
vector avg = {0,0,0};
foreach(int n; npts){ avg += point(0,'P',n); }
avg /= max(1, len(npts));
@P = lerp(@P, avg, 0.3);

float freq = 2.0;
float amp = 0.5;
@P.y += sin(@Time * freq * PI * 2 + @ptnum * 0.1) * amp;

float freq = 1.5;
float amp = 0.3;
vector offset = set(@ptnum*0.1, 0, @ptnum*0.3);
@P += @N * turbulent_noise(@P * freq + offset, 4) * amp;

vector axis = normalize({1,1,0});
float angle = radians(45);
matrix3 m = ident();
rotate(m, angle, axis);
@P *= m;

vector grad_x, grad_y, grad_z;
float freq = 0.5;
vector p = @P * freq;
curl_noise(p, grad_x, grad_y, grad_z);
v@v = set(grad_y.z - grad_z.y,
          grad_z.x - grad_x.z,
          grad_x.y - grad_y.x);

vector up = {0,1,0};
vector vel = normalize(v@v);
if (length(v@v) < 0.001) vel = up;
vector right = normalize(cross(vel, up));
vector realup = cross(right, vel);
matrix3 m = set(right, realup, vel);
@orient = quaternion(m);

// Store 2 shorts in a single int attribute
int lo = int(@myval_a) & 0xFFFF;
int hi = (int(@myval_b) & 0xFFFF) << 16;
i@packed = lo | hi;
// Unpack:
int a = i@packed & 0xFFFF;
int b = (i@packed >> 16) & 0xFFFF;

vector pos, bound_pos;
float dist_to_edge;
olvdf(3, @P, 1.5, pos, bound_pos, dist_to_edge);
@Cd = rand(pos * 17.3);

vector plane_n = normalize({0,1,0.5});
vector plane_p = {0,0,0};
float d = dot(@P - plane_p, plane_n);
@P -= d * plane_n;

float t = fit(@myattr, 0, 1, 0, 1);
t = t*t*(3.0 - 2.0*t); // smoothstep
@P.y += t * 2.0;

vector hitpos, hitnml;
float dist;
int hit = intersect(1, @P, {0,-1,0} * 100, hitpos, hitnml);
if (hit >= 0) @P = hitpos;

int nbs[] = pcfind(0, 'P', @P, 0.8, 4);
foreach(int nb; nbs){
  if(nb > @ptnum)
    addprim(0, 'polyline', @ptnum, nb);
}

float a = 3.0, b = 4.0;
float val = cos(a * PI * @P.x) * cos(b * PI * @P.z)
          - cos(b * PI * @P.x) * cos(a * PI * @P.z);
if(abs(val) < 0.05) @Cd = {1,1,0};
else @Cd = {0.1,0.1,0.1};

